using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_05f26a7bc05d493da28149f3c0c36015.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_05f26a7bc05d493da28149f3c0c36015.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* STEP 1 — Patient Information *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label>Patient Name:</label>
            <InputText @bind-Value="model.PatientName" class="form-control" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label>Email:</label>
            <InputText @bind-Value="model.Email" class="form-control" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label>Phone:</label>
            <InputText @bind-Value="model.Phone" class="form-control" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label>Insurance Provider:</label>
            <InputSelect @bind-Value="model.InsuranceProvider" class="form-control">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* STEP 2 — Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label>Preferred Doctor:</label>
                <InputSelect @bind-Value="model.PreferredDoctor" class="form-control"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doctor in doctors)
                    {
                        <option value="@doctor">@doctor</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.PreferredDoctor" />
            </div>

            <div class="mb-3">
                <label>Date:</label>
                <InputDate @bind-Value="model.AppointmentDate" class="form-control"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label>Time Slot:</label>
                <InputSelect @bind-Value="model.TimeSlot" class="form-control">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label>Reason for Visit:</label>
                <InputTextArea @bind-Value="model.ReasonForVisit" class="form-control" rows="4" />
                <ValidationMessage For="() => model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability"
                    disabled="@isChecking">
                @(isChecking ? "Checking..." : "Check Availability")
            </button>

            <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed || isSubmitting)">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>

            @if (availabilityConfirmed)
            {
                <div class="alert alert-success mt-3">
                    ✓ Availability confirmed. You may submit the appointment.
                </div>
            }
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-info mt-4">
        Appointment booked successfully for <strong>@model.PatientName</strong>
        with <strong>@model.PreferredDoctor</strong> on @model.AppointmentDate?.ToString("MMM dd, yyyy")
        at @model.TimeSlot.
    </div>
}

@code {
    private AppointmentModel model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool availabilityConfirmed;
    private bool submitted;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step 1 fields
        var step1Valid = true;
        var step1Fields = new[] {
            nameof(AppointmentModel.PatientName),
            nameof(AppointmentModel.Email),
            nameof(AppointmentModel.Phone),
            nameof(AppointmentModel.InsuranceProvider)
        };

        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
        }

        // Check if step 1 fields have validation errors
        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                step1Valid = false;
            }
        }

        if (step1Valid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        if (!string.IsNullOrEmpty(model.PreferredDoctor) && model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.PreferredDoctor, model.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityConfirmed = false;

        // Validate step 2 fields locally first
        var step2Fields = new[] {
            nameof(AppointmentModel.PreferredDoctor),
            nameof(AppointmentModel.AppointmentDate),
            nameof(AppointmentModel.TimeSlot),
            nameof(AppointmentModel.ReasonForVisit)
        };

        foreach (var field in step2Fields)
        {
            editContext!.NotifyFieldChanged(editContext.Field(field));
        }

        var hasLocalErrors = step2Fields.Any(f =>
            editContext!.GetValidationMessages(editContext.Field(f)).Any());

        if (hasLocalErrors) return;

        isChecking = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email!,
                model.InsuranceProvider!,
                model.PreferredDoctor!,
                model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityConfirmed) return;

        isSubmitting = true;
        try
        {
            // Simulate booking delay
            await Task.Delay(500);
            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

