@page "/book-appointment"
@rendermode InteractiveServer
@using sv_05f26a7bc05d493da28149f3c0c36015.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* STEP 1 — Patient Information *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label>Patient Name:</label>
            <InputText @bind-Value="model.PatientName" class="form-control" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label>Email:</label>
            <InputText @bind-Value="model.Email" class="form-control" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label>Phone:</label>
            <InputText @bind-Value="model.Phone" class="form-control" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label>Insurance Provider:</label>
            <InputSelect @bind-Value="model.InsuranceProvider" class="form-control">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* STEP 2 — Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label>Preferred Doctor:</label>
                <InputSelect @bind-Value="model.PreferredDoctor" class="form-control"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doctor in doctors)
                    {
                        <option value="@doctor">@doctor</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.PreferredDoctor" />
            </div>

            <div class="mb-3">
                <label>Date:</label>
                <InputDate @bind-Value="model.AppointmentDate" class="form-control"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label>Time Slot:</label>
                <InputSelect @bind-Value="model.TimeSlot" class="form-control">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label>Reason for Visit:</label>
                <InputTextArea @bind-Value="model.ReasonForVisit" class="form-control" rows="4" />
                <ValidationMessage For="() => model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability"
                    disabled="@isChecking">
                @(isChecking ? "Checking..." : "Check Availability")
            </button>

            <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed || isSubmitting)">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>

            @if (availabilityConfirmed)
            {
                <div class="alert alert-success mt-3">
                    ✓ Availability confirmed. You may submit the appointment.
                </div>
            }
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-info mt-4">
        Appointment booked successfully for <strong>@model.PatientName</strong>
        with <strong>@model.PreferredDoctor</strong> on @model.AppointmentDate?.ToString("MMM dd, yyyy")
        at @model.TimeSlot.
    </div>
}

